// STEP 2 — Photos
// ═══════════════════════════════════════════════════════════════════════

function handlePhotos(input) {
  const files = Array.from(input.files);
  photoMap = {};
  photoOrderList = []; // ordered list of dataURLs matching row order

  const promises = files.map((f, fileIndex) => new Promise(res => {
    const reader = new FileReader();
    reader.onload = e => {
      const dataURL = e.target.result;
      // Remove background in browser then store
      removeBgInBrowser(dataURL).then(cleanURL => {
        const lower = f.name.toLowerCase();
        const noExt = lower.replace(/\.[^.]+$/, "");
        // Name-based map (normalized)
        photoMap[lower]  = cleanURL;
        photoMap[noExt]  = cleanURL;
        photoMap[normalize(noExt)] = cleanURL;
        // Order-based: sort files by name so order is deterministic
        photoOrderList.push({ name: noExt, url: cleanURL, origName: f.name });
        res();
      });
    };
    reader.readAsDataURL(f);
  }));

  Promise.all(promises).then(() => {
    // Sort photoOrderList alphabetically so upload order doesn't matter
    photoOrderList.sort((a, b) => a.name.localeCompare(b.name));
    // Use first photo for editor preview
    if (photoOrderList.length > 0) {
      const img = new Image();
      img.onload = () => { editorPhotoImg = img; renderEditor(); };
      img.src = photoOrderList[0].url;
    }
    showStatus("photoStatus", `✅ ${files.length} photo(s) uploaded & backgrounds removed`, "ok");
    document.getElementById("step2").classList.add("done");
    updateStudentList();
    checkReady();
  });
}

// ── Background removal via Hugging Face Space ────────────────────────
const HF_SPACE_URL = "https://aishaani-koala-rembg.hf.space";

async function removeBgInBrowser(dataURL) {
  try {
    // Convert dataURL to blob
    const fetchRes = await fetch(dataURL);
    const blob     = await fetchRes.blob();
    const file     = new File([blob], "photo.png", { type: "image/png" });

    // Send to /remove-bg endpoint
    const fd = new FormData();
    fd.append("file", file);

    const res = await fetch(`${HF_SPACE_URL}/remove-bg`, {
      method: "POST",
      body: fd
    });

    if (!res.ok) throw new Error("Server error: " + res.status);

    const resultBlob = await res.blob();
    return await blobToDataURL(resultBlob);

  } catch (err) {
    console.warn("BG removal failed, using crop only:", err.message);
    return cropOnly(dataURL, 0.90);
  }
}

function blobToDataURL(blob) {
  return new Promise(res => {
    const reader = new FileReader();
    reader.onload = e => res(e.target.result);
    reader.readAsDataURL(blob);
  });
}

function cropOnly(dataURL, pct) {
  return new Promise(res => {
    const img = new Image();
    img.onload = () => {
      const cropH = Math.floor(img.height * pct);
      const c = document.createElement("canvas");
      c.width = img.width; c.height = cropH;
      c.getContext("2d").drawImage(img, 0, 0);
      res(c.toDataURL("image/png"));
    };
    img.src = dataURL;
  });
}






// ── Order-based photo lookup ─────────────────────────────────────────
function getPhotoByIndex(index) {
  if (photoOrderList && photoOrderList[index]) return photoOrderList[index].url;
  return null;
}

function normalize(str) {
  return str.toLowerCase()
    .replace(/_{2,}/g, " ")
    .replace(/_/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function findPhoto(student) {
  const name = normalize(student.name || "");
  if (!name) return null;

  // Exact normalized match
  for (const [key, dataURL] of Object.entries(photoMap)) {
    const normKey = normalize(key.replace(/\.[^.]+$/, ""));
    if (normKey === name) return dataURL;
  }

  // All words match
  const words = name.split(" ").filter(w => w.length > 1);
  for (const [key, dataURL] of Object.entries(photoMap)) {
    const normKey = normalize(key.replace(/\.[^.]+$/, ""));
    if (words.every(w => normKey.includes(w))) return dataURL;
  }

  // First + last name
  const parts = name.split(" ");
  const first = parts[0];
  const last = parts[parts.length - 1];
  for (const [key, dataURL] of Object.entries(photoMap)) {
    const normKey = normalize(key.replace(/\.[^.]+$/, ""));
    if (normKey.includes(first) && (last === first || normKey.includes(last))) return dataURL;
  }

  return null;
}

// ── Student list ──────────────────────────────────────────────────────
function updateStudentList() {
  if (!mappedData.length) return;
  const wrap = document.getElementById("studentListWrap");
  const list = document.getElementById("studentList");
  wrap.style.display = "block";
  const useOrderMatch = photoOrderList.length > 0;
  list.innerHTML = mappedData.map((s,i) => {
    const photo = useOrderMatch ? getPhotoByIndex(i) : findPhoto(s);
    const label = useOrderMatch
      ? (photo ? `📷 #${i+1} ✓` : "⚠ no photo")
      : (photo ? "📷 name ✓"  : "⚠ no photo");
    return `<div class="student-row">
      <span class="snum">${i+1}</span>
      <span class="sname">${s.name || "(no name)"}</span>
      <span class="sdob">${s.dob || ""}</span>
      <span class="sphoto ${photo ? 'found' : 'warn'}">${label}</span>
    </div>`;
  }).join("");
}

function checkReady() {
  document.getElementById("genBtn").disabled = students.length === 0;
}

// ═══════════════════════════════════════════════════════════════════════
// GENERATE
// ═══════════════════════════════════════════════════════════════════════

async function generateAll() {
  updateMappedData();
  const btn = document.getElementById("genBtn");
  btn.disabled = true; btn.textContent = "⏳ Generating...";
  document.getElementById("progressWrap").style.display = "block";
  renderedCards = [];
  const total = mappedData.length;
  await waitForImages();
  await document.fonts.ready;

  for (let i = 0; i < total; i++) {
    const s = mappedData[i];
    document.getElementById("progressBar").style.width = Math.round((i/total)*100) + "%";
    document.getElementById("progressLabel").textContent = `Generating ${i+1} of ${total}: ${s.name || "student"}`;
    const photoURL = (photoOrderList.length > 0) ? getPhotoByIndex(i) : findPhoto(s);
    const photoImg = await loadImage(photoURL);
    const fc = makeCanvas(); drawFront(fc.getContext("2d"), s, photoImg, positions.front);
    const bc = makeCanvas(); drawBack(bc.getContext("2d"), s, positions.back);
    const safeName = (s.name || `student_${i+1}`).replace(/\s+/g, "_");
    renderedCards.push({ name: s.name || `student_${i+1}`, safeName, frontDataURL: fc.toDataURL("image/png"), backDataURL: bc.toDataURL("image/png") });
    await sleep(10);
  }
  document.getElementById("progressBar").style.width = "100%";
  document.getElementById("progressLabel").textContent = `✅ ${total} card(s) ready!`;
  btn.disabled = false; btn.textContent = "🔄 Regenerate";
  previewIndex = 0; showPreview();
}

// ── Draw front ────────────────────────────────────────────────────────
function drawFront(ctx, student, photoImg, fields) {
  ctx.drawImage(activeFrontImg(), 0, 0, W, H);
  if (photoImg) {
    const b = photoSettings;
    const cx = b.x + b.w/2, cy = b.y + b.h/2;
    const baseScale = Math.max(b.w/photoImg.width, b.h/photoImg.height);
    const scale = baseScale * (photoSettings.scale / 100);
    const sw = photoImg.width*scale, sh = photoImg.height*scale;
    const tiltRad = (photoSettings.tilt * Math.PI) / 180;
    ctx.save();
    // Move to center, rotate, THEN clip — so clip rotates with the photo
    ctx.translate(cx, cy);
    ctx.rotate(tiltRad);
    ctx.beginPath();
    ctx.rect(-b.w/2, -b.h/2, b.w, b.h);
    ctx.clip();
    ctx.drawImage(photoImg, -sw/2, -sh/2, sw, sh);
    ctx.restore();
  }
  ctx.textBaseline = "top";
  for (const f of fields) {
    ctx.font = `bold ${f.size}px ${FONT_FACE}`;
    const value = student[f.key] || "";
    if (f.centered) {
      // Draw "Label:" (pink) + value (grey) as ONE unit, centred on f.centerX.
      // Width adapts to the name, so the whole block re-centres for every student.
      // The pink label can be a different (bigger) size than the grey value.
      const labelText = f.labelText || (f.label + ":");
      const gap = f.gap != null ? f.gap : 8;
      const labelSize = f.labelSize != null ? f.labelSize : f.size;
      // Measure label at its own size
      ctx.font = `bold ${labelSize}px ${FONT_FACE}`;
      const labelW = ctx.measureText(labelText).width;
      // Measure value at its size
      ctx.font = `bold ${f.size}px ${FONT_FACE}`;
      const valueW = ctx.measureText(value).width;
      const totalW = labelW + gap + valueW;
      const centerX = f.centerX != null ? f.centerX : W / 2;
      const startX = centerX - totalW / 2;
      // Bottom-align both so the bigger label and smaller value share a baseline.
      const baseY = f.y + Math.max(labelSize, f.size);
      ctx.textBaseline = "alphabetic";
      ctx.fillStyle = LABEL_COLOR;
      ctx.font = `bold ${labelSize}px ${FONT_FACE}`;
      ctx.fillText(labelText, startX, baseY);
      ctx.fillStyle = VALUE_COLOR;
      ctx.font = `bold ${f.size}px ${FONT_FACE}`;
      ctx.fillText(value, startX + labelW + gap, baseY);
      ctx.textBaseline = "top";
    } else {
      ctx.fillStyle = VALUE_COLOR;
      ctx.fillText(value, f.x, f.y);
    }
  }
}

// ── Draw back ─────────────────────────────────────────────────────────
function drawBack(ctx, student, fields) {
  ctx.drawImage(activeBackImg(), 0, 0, W, H);
  ctx.textBaseline = "top"; ctx.textAlign = "left"; ctx.fillStyle = VALUE_COLOR;
  for (const f of fields) {
    ctx.font = `bold ${f.size}px ${FONT_FACE}`;
    if (f.wrap && f.inlineStart) {
      wrapTextInline(ctx, student[f.key] || "", f.x, f.y, f.size, f.maxLines || 3, f.wrapX || 38);
    } else if (f.wrap) {
      wrapText(ctx, student[f.key] || "", f.x, f.y, f.wrapWidth || 370, f.size + 4, f.maxLines);
    } else {
      ctx.fillText(student[f.key] || "", f.x, f.y);
    }
  }
}

// Inline wrap: line 1 starts at x (right after the printed label) and uses the
// space left on that line. Lines 2+ start at wrapX (under the label, full
// width). If the text needs more than maxLines lines, the font auto-shrinks.
function wrapTextInline(ctx, text, x, y, baseSize, maxLines, wrapX) {
  if (!text) return;
  ctx.textAlign = "left";
  const words = String(text).split(/\s+/).filter(Boolean);
  const limit = maxLines || 3;
  const line1Width = W - x - 14;      // space remaining next to the label
  const contWidth  = W - wrapX - 14;  // full width for lines 2 and 3

  let size = baseSize, lines = [];
  while (size >= 8) {
    ctx.font = `bold ${size}px ${FONT_FACE}`;
    lines = layoutInline(ctx, words, line1Width, contWidth);
    if (lines.length <= limit) break;
    size -= 0.5;                      // too long → shrink font and retry
  }

  const lineHeight = size + 4;
  lines.forEach((line, i) => {
    ctx.fillText(line, i === 0 ? x : wrapX, y + i * lineHeight);
  });
}

// Greedy word wrap: first line capped at line1Width, the rest at contWidth.
function layoutInline(ctx, words, line1Width, contWidth) {
  const lines = [];
  let line = "";
  for (const word of words) {
    const test = line ? line + " " + word : word;
    const max  = lines.length === 0 ? line1Width : contWidth;
    if (line && ctx.measureText(test).width > max) {
      lines.push(line);
      line = word;
    } else {
      line = test;
    }
  }
  if (line) lines.push(line);
  return lines;
}

// ── Preview ───────────────────────────────────────────────────────────
function showPreview() {
  document.getElementById("previewSection").style.display = "block";
  const card = renderedCards[previewIndex];
  document.getElementById("navLabel").textContent = `${card.name} (${previewIndex+1} of ${renderedCards.length})`;
  document.getElementById("prevBtn").disabled = previewIndex === 0;
  document.getElementById("nextBtn").disabled = previewIndex === renderedCards.length-1;
  drawOnCanvas("prevFront", card.frontDataURL);
  drawOnCanvas("prevBack",  card.backDataURL);
}
function previewNav(dir) {
  previewIndex = Math.max(0, Math.min(renderedCards.length-1, previewIndex+dir));
  showPreview();
}
function drawOnCanvas(id, dataURL) {
  const img = new Image(); img.onload = () => document.getElementById(id).getContext("2d").drawImage(img, 0, 0, 434, 669); img.src = dataURL;
}

// ── Download ZIP ──────────────────────────────────────────────────────
async function downloadZip() {
  if (!renderedCards.length) return;
  const btn = document.querySelector('.dl-all-btn');
  btn.textContent = "⏳ Creating ZIP..."; btn.disabled = true;
  const zip = new JSZip();
  const folder = zip.folder("koala_id_cards");
  for (const card of renderedCards) {
    folder.file(`${card.safeName}_front.png`, card.frontDataURL.split(",")[1], { base64: true });
    folder.file(`${card.safeName}_back.png`,  card.backDataURL.split(",")[1],  { base64: true });
  }
  const blob = await zip.generateAsync({ type: "blob" });
  const a = document.createElement("a"); a.href = URL.createObjectURL(blob); a.download = "koala_id_cards.zip"; a.click();
  btn.textContent = "⬇ Download All Cards as ZIP"; btn.disabled = false;
}

// ═══════════════════════════════════════════════════════════════════════
// UTILITIES
// ═══════════════════════════════════════════════════════════════════════
function makeCanvas() { const c = document.createElement("canvas"); c.width=W; c.height=H; return c; }
function loadImage(dataURL) { return new Promise(res => { if (!dataURL) return res(null); const img = new Image(); img.onload=()=>res(img); img.onerror=()=>res(null); img.src=dataURL; }); }
function waitForImages() { return new Promise(res => { if (imagesReady>=2) return res(); const t=setInterval(()=>{ if(imagesReady>=2){clearInterval(t);res();}},100); }); }
function sleep(ms) { return new Promise(res => setTimeout(res, ms)); }
function wrapText(ctx, text, x, y, maxWidth, lineHeight, maxLines) {
  if (!text) return;
  const words = String(text).split(" ");
  let line="", lineY=y, lineCount=0;
  const limit = maxLines || 99;
  for (const word of words) {
    const test = line ? line+" "+word : word;
    if (ctx.measureText(test).width > maxWidth && line) {
      ctx.fillText(line, x, lineY);
      line=word; lineY+=lineHeight; lineCount++;
      if (lineCount >= limit - 1) {
        // Last line — fit remaining
        ctx.fillText(words.slice(words.lastIndexOf(word)).join(" "), x, lineY);
        return;
      }
    } else { line=test; }
  }
  if (line) ctx.fillText(line, x, lineY);
}
function showStatus(id, msg, type) { document.getElementById(id).innerHTML = `<div class="status-tag ${type}">${msg}</div>`; }